                              </div>
                              {isRecording && (
                                <div style={{
                                  color: '#ef4444',
                                  fontSize: '13px',
                                  fontWeight: '600',
                                  display: 'flex',
                                  alignItems: 'center',
                                  gap: '6px',
                                  marginTop: '8px'
